// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with safe configuration
	L := lua.NewState(lua.Options{
		CallStackSize:       128,  // Limit call stack depth
		RegistrySize:        256,  // Limit registry size
		SkipOpenLibs:        true, // Don't load standard libraries by default
		IncludeGoStackTrace: false, // Don't include Go stack traces in errors
	})
	defer L.Close()

	// Load only safe base libraries
	L.OpenLibs()

	// Remove dangerous functions from the global environment
	dangerousFuncs := []string{
		"dofile", "loadfile", "load", "loadstring",
		"io", "os", "debug", "package", "module",
	}
	for _, fn := range dangerousFuncs {
		L.SetGlobal(fn, lua.LNil)
	}

	// Set up execution timeout
	done := make(chan bool, 1)
	var resultErr error
	var luaResult float64

	go func() {
		defer func() {
			if r := recover(); r != nil {
				resultErr = fmt.Errorf("Lua VM panic: %v", r)
			}
			done <- true
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			resultErr = fmt.Errorf("failed to execute Lua script: %w", err)
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			resultErr = fmt.Errorf("calculate_final_price is not a function or not defined")
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			resultErr = fmt.Errorf("failed to call calculate_final_price: %w", err)
			return
		}

		// Get the result from the Lua stack
		result := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if result.Type() != lua.LTNumber {
			resultErr = fmt.Errorf("calculate_final_price did not return a number")
			return
		}

		luaResult = float64(result.(lua.LNumber))
	}()

	// Wait for completion or timeout
	select {
	case <-done:
		return luaResult, resultErr
	case <-time.After(2 * time.Second): // 2 second timeout
