import (
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with security restrictions
	L := lua.NewState(lua.Options{
		// Limit execution time to prevent DoS attacks
		CallStackSize:       100,
		RegistrySize:        1000,
		SkipOpenLibs:        true, // Disable standard libraries for security
		IncludeGoStackTrace: true,
	})
	defer L.Close()

	// Initialize the package.preload table before loading modules
	// This is required when SkipOpenLibs is true
	preload := L.NewTable()
	L.SetField(L.Get(lua.RegistryIndex), "_PRELOAD", preload)

	// Load only safe libraries (math, string, table) - remove dangerous ones
	L.PreloadModule("base", lua.OpenBase)
	L.PreloadModule("package", lua.OpenPackage)
	L.PreloadModule("table", lua.OpenTable)
	L.PreloadModule("string", lua.OpenString)
	L.PreloadModule("math", lua.OpenMath)

	// Remove dangerous functions from global namespace
	L.SetGlobal("dofile", lua.LNil)
	L.SetGlobal("loadfile", lua.LNil)
	L.SetGlobal("load", lua.LNil)
	L.SetGlobal("loadstring", lua.LNil)
	L.SetGlobal("io", lua.LNil)
	L.SetGlobal("os", lua.LNil)
	L.SetGlobal("debug", lua.LNil)
	L.SetGlobal("module", lua.LNil)

	// Create a channel to handle timeout
	resultChan := make(chan struct {
		val float64
		err error
	}, 1)

	// Execute script in a goroutine with timeout
	go func() {
		// Load and execute the script
		if err := L.DoString(script); err != nil {
			resultChan <- struct {
				val float64
				err error
			}{0, fmt.Errorf("failed to execute Lua script: %w", err)}
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			resultChan <- struct {
				val float64
				err error
			}{0, fmt.Errorf("calculate_final_price is not a function or not defined")}
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			resultChan <- struct {
				val float64
				err error
			}{0, fmt.Errorf("failed to call calculate_final_price: %w", err)}
			return
		}

		// Get the result from the Lua stack
		result := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if result.Type() != lua.LTNumber {
			resultChan <- struct {
				val float64
				err error
			}{0, fmt.Errorf("calculate_final_price did not return a number")}
			return
		}

		resultChan <- struct {
			val float64
			err error
		}{float64(result.(lua.LNumber)), nil}
	}()

	// Wait for result or timeout
	select {
	case res := <-resultChan:
		return res.val, res.err
	case <-time.After(5 * time.Second): // 5 second timeout
		// Forcefully close the Lua state to stop execution
		L.Close()
		return 0, fmt.Errorf("execution timeout - script took too long")
	}
}

