package main

import (
	"fmt"
	"strings"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a Lua script that defines a calculate_final_price function.
// It takes the Lua script as a string and a context map with string keys and float64 values.
// The function returns the calculated price as a float64 or an error if execution fails.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Load and execute the script to define the calculate_final_price function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %v", err)
	}

	// Get the calculate_final_price function from the global environment
	luaFunc := L.GetGlobal("calculate_final_price")
	if luaFunc.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function (got %s)", luaFunc.Type())
	}

	// Convert the Go map to a Lua table
	luaTable := L.NewTable()
	for key, value := range ctx {
		L.SetField(luaTable, key, lua.LNumber(value))
	}

	// Call the Lua function with the context table as argument
	L.Push(luaFunc)
	L.Push(luaTable)
	if err := L.PCall(1, 1, nil); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %v", err)
	}

	// Get and validate the return value
	ret := L.Get(-1)
	L.Pop(1) // Remove the returned value from stack

	if ret.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price must return a number (got %s)", ret.Type())
	}

	// Convert Lua number to Go float64
	result, ok := ret.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("failed to convert Lua number to float64")
	}

	return float64(result), nil
}

func main() {
	// Example usage
	script := `
