	// This prevents "attempt to index a non-table object(nil) with key 'preload'" error
	loaded := L.NewTable()
	L.SetField(L.Get(lua.RegistryIndex), "_LOADED", loaded)
	preload := L.NewTable()
	L.SetField(loaded, "preload", preload)

	// Also set up the global package table for compatibility
	packageTable := L.NewTable()
	L.SetField(packageTable, "preload", preload)
	L.SetGlobal("package", packageTable)

	// Set execution timeout to prevent infinite loops
	executionTimeout := 5 * time.Second
	contextWithTimeout, cancel := context.WithTimeout(context.Background(), executionTimeout)
	defer cancel()
	L.SetContext(contextWithTimeout)

	// Only open safe libraries
	L.PreloadModule("math", lua.OpenMath)
	L.PreloadModule("string", lua.OpenString)
	L.PreloadModule("table", lua.OpenTable)

	// Load and execute the script
