	case err := <-errChan:
		return 0, err
	case <-execCtx.Done():
		return 0, fmt.Errorf("execution timeout exceeded")
	}
}

// setupSecureEnvironment configures a secure Lua environment with only safe functions
func setupSecureEnvironment(L *lua.LState) {
	// Initialize package table for module loading
	packageTable := L.CreateTable(0, 1)
	preloadTable := L.CreateTable(0, 0)
	packageTable.RawSetString("preload", preloadTable)
	L.SetGlobal("package", packageTable)

	// Only allow safe base functions
	baseOpen := L.CreateTable(0, len(safeBaseFuncs))
	for name, fn := range safeBaseFuncs {
		baseOpen.RawSetString(name, L.NewFunction(fn))
	}
	L.SetGlobal("_G", baseOpen)

	// Allow math library (safe for calculations)
	L.PreloadModule("math", lua.OpenMath)

	// Allow table library (safe for data manipulation)
	L.PreloadModule("table", lua.OpenTable)

	// Remove dangerous functions
	removeDangerousFunctions(L)
}

// safeBaseFuncs contains only safe base Lua functions
var safeBaseFuncs = map[string]lua.LGFunction{
	"type":   luaBaseType,
	"next":   luaBaseNext,
	"pairs":  luaBasePairs,
	"ipairs": luaBaseIPairs,
	"print":  luaBasePrint,
	"select": luaBaseSelect,
	"tonumber": func(L *lua.LState) int {
		arg := L.CheckAny(1)
		if num, ok := arg.(lua.LNumber); ok {
			L.Push(num)
			return 1
		}
		if str, ok := arg.(lua.LString); ok {
			// Simple number parsing without side effects
			var n lua.LNumber
			_, err := fmt.Sscanf(string(str), "%f", &n)
			if err == nil {
				L.Push(n)
				return 1
			}
		}
		L.Push(lua.LNil)
		return 1
	},
	"tostring": func(L *lua.LState) int {
		arg := L.CheckAny(1)
		L.Push(lua.LString(arg.String()))
		return 1
	},
}

// removeDangerousFunctions removes or neutralizes dangerous Lua functions
func removeDangerousFunctions(L *lua.LState) {
	// Remove functions that could cause security issues
	dangerousFuncs := []string{
		"load", "loadfile", "dofile", "require",
		"getfenv", "setfenv", "newproxy",
		"collectgarbage", "gcinfo",
		"debug", "getmetatable", "setmetatable",
		"rawget", "rawset", "rawequal", "rawlen",
		"pcall", "xpcall", // Can be used to bypass restrictions
	}

	for _, name := range dangerousFuncs {
		L.SetGlobal(name, lua.LNil)
	}
}

// Safe implementations of base functions
func luaBaseType(L *lua.LState) int {
	L.Push(lua.LString(L.CheckAny(1).Type().String()))
	return 1
}

func luaBaseNext(L *lua.LState) int {
	tbl := L.CheckTable(1)
	key := L.CheckAny(2)
	if key == lua.LNil {
		key = lua.LNil
	}
	nextKey, nextValue := tbl.Next(key)
	if nextKey == lua.LNil {
		L.Push(lua.LNil)
		return 1
	}
	L.Push(nextKey)
	L.Push(nextValue)
	return 2
}

func luaBasePairs(L *lua.LState) int {
	tbl := L.CheckTable(1)
	L.Push(L.NewFunction(func(L *lua.LState) int {
		key := L.CheckAny(2)
		if key == lua.LNil {
			key = lua.LNil
		}
		nextKey, nextValue := tbl.Next(key)
		if nextKey == lua.LNil {
			L.Push(lua.LNil)
			return 1
		}
		L.Push(nextKey)
		L.Push(nextValue)
		return 2
	}))
	L.Push(tbl)
	L.Push(lua.LNil)
	return 3
}

func luaBaseIPairs(L *lua.LState) int {
	tbl := L.CheckTable(1)
	L.Push(L.NewFunction(func(L *lua.LState) int {
		idx := L.CheckInt(2) + 1
		val := L.GetTable(tbl, lua.LNumber(idx))
		if val == lua.LNil {
			L.Push(lua.LNil)
			return 1
		}
		L.Push(lua.LNumber(idx))
		L.Push(val)
		return 2
	}))
	L.Push(tbl)
	L.Push(lua.LNumber(0))
	return 3
}

func luaBasePrint(L *lua.LState) int {
	// Safe print that doesn't expose system information
	top := L.GetTop()
	for i := 1; i <= top; i++ {
		if i > 1 {
			fmt.Print("\t")
		}
		fmt.Print(L.Get(i).String())
	}
	fmt.Println()
	return 0
}

func luaBaseSelect(L *lua.LState) int {
	n := L.GetTop()
	if n < 1 {
		L.RaiseError("select: needs at least one argument")
	}
	first := L.CheckAny(1)
	if lv, ok := first.(lua.LString); ok && string(lv) == "#" {
		L.Push(lua.LNumber(n - 1))
		return 1
	}
	idx := L.CheckInt(1)
	if idx < 0 {
		idx = n + idx
	} else if idx > n {
		idx = n
	}
	for i := idx; i <= n; i++ {
		L.Push(L.Get(i))
	}
	return n - idx + 1
}

